content.query:
// Translation progress summary
let book_filter = '{BookId}';
let translated = customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.pipeline.chunks_translated'
| extend book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize Translated = sum(value);
let failed = customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.translation.errors'
| extend book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize Failed = sum(value);
let tokens = customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.openai.tokens_used'
| extend book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize Tokens = sum(value);
let cost = customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.translation.estimated_cost_usd'
| extend book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize Cost_USD = round(sum(value), 2);
translated | extend d=1
| join (failed | extend d=1) on d
| join (tokens | extend d=1) on d
| join (cost | extend d=1) on d
| project ['Chunks Translated'] = Translated, ['Chunks Failed'] = Failed, ['Total Tokens'] = Tokens, ['Est. Cost (USD)'] = Cost_USD

// Translation throughput over time (chunks per 5 minutes)
let book_filter = '{BookId}';
customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.pipeline.chunks_translated'
| extend book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize chunks = sum(value) by bin(timestamp, 5m)
| order by timestamp asc

// Cumulative translation progress
let book_filter = '{BookId}';
customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.pipeline.chunks_translated'
| extend book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize chunks = sum(value) by bin(timestamp, 1m)
| order by timestamp asc
| extend cumulative = row_cumsum(chunks)

// Token consumption over time
let book_filter = '{BookId}';
customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.openai.tokens_used'
| extend book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize tokens = sum(value) by bin(timestamp, 5m)
| order by timestamp asc

// Stage duration stacked bar — shows where time is spent per pipeline run
let book_filter = '{BookId}';
customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.pipeline.stage_duration'
| extend stage = tostring(customDimensions.stage), book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| where stage != 'total'
| summarize duration_s = round(avg(value), 1) by book_id, stage
| order by book_id asc

// Stage duration trend over time
let book_filter = '{BookId}';
customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.pipeline.stage_duration'
| extend stage = tostring(customDimensions.stage), book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| where stage != 'total'
| summarize avg_duration = round(avg(value), 1) by stage, bin(timestamp, 10m)
| order by timestamp asc

// Error rate by stage and type
let book_filter = '{BookId}';
customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.errors'
| extend stage = tostring(customDimensions.stage), error_type = tostring(customDimensions.error_type), book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize error_count = sum(value) by stage, error_type
| order by error_count desc

// Error timeline
let book_filter = '{BookId}';
customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.errors'
| extend stage = tostring(customDimensions.stage), book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize errors = sum(value) by stage, bin(timestamp, 5m)
| order by timestamp asc

// Content filter events
let book_filter = '{BookId}';
let blocks = customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.translation.content_filter_blocks'
| extend book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize Blocked = sum(value);
let recovered = customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.translation.content_filter_fallback_success'
| extend book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize Recovered = sum(value);
blocks | extend d=1
| join (recovered | extend d=1) on d
| project ['Content Filter Blocks'] = Blocked, ['Recovered via Fallback'] = Recovered, ['Unrecoverable'] = Blocked - Recovered, ['Recovery Rate %'] = iff(Blocked > 0, round(Recovered / Blocked * 100, 1), 0.0)

// Translation-specific errors (content_filter, rate_limit, etc.)
let book_filter = '{BookId}';
customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.translation.errors'
| extend error_type = tostring(customDimensions.error_type), book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize count = sum(value) by error_type
| order by count desc

// Pipeline success vs failure rate
let book_filter = '{BookId}';
let total_runs = customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.pipeline.stage_duration'
| extend stage = tostring(customDimensions.stage), book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| where stage == 'total'
| summarize total = count();
let failed = customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.errors'
| extend stage = tostring(customDimensions.stage), error_type = tostring(customDimensions.error_type), book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| where error_type == 'QualityGateError' or stage == 'unknown'
| summarize failed_count = dcount(book_id);
total_runs | extend d=1
| join (failed | extend d=1) on d
| project ['Total Runs'] = total, ['Failed'] = failed_count, ['Success Rate %'] = iff(total > 0, round((total - failed_count) * 100.0 / total, 1), 0.0)

// OCR quality summary
let book_filter = '{BookId}';
let total = customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.ocr.pages_processed'
| extend book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize pages = sum(value);
let low = customMetrics
| where timestamp {TimeRange}
| where name == 'transpose.ocr.low_confidence_pages'
| extend book_id = tostring(customDimensions.book_id)
| where book_filter == '' or book_id == book_filter
| summarize low_conf = sum(value);
total | extend d=1
| join (low | extend d=1) on d
| project ['Pages Processed'] = pages, ['Low Confidence'] = low_conf, ['Quality %'] = iff(pages > 0, round((pages - low_conf) * 100.0 / pages, 1), 0.0)
